import{_ as e,o as r,c as h,ah as n}from"./chunks/framework.Bg572dcY.js";const b=JSON.parse('{"title":"Neo4j","description":"","frontmatter":{"title":"Neo4j","order":4},"headers":[],"relativePath":"server/db/nosql/neo4j.md","filePath":"server/db/nosql/neo4j.md"}'),l={name:"server/db/nosql/neo4j.md"};function i(o,a,t,p,d,s){return r(),h("div",null,[...a[0]||(a[0]=[n('<h1 id="neo4j-实现原理" tabindex="-1">Neo4j 实现原理 <a class="header-anchor" href="#neo4j-实现原理" aria-label="Permalink to “Neo4j 实现原理”">​</a></h1><p>Neo4j 是原生图数据库，专注于存储和查询图结构数据。理解 Neo4j 的实现，需要深入图数据模型、存储引擎、索引机制和 Cypher 查询语言。</p><h2 id="图数据模型" tabindex="-1">图数据模型 <a class="header-anchor" href="#图数据模型" aria-label="Permalink to “图数据模型”">​</a></h2><h3 id="标签属性图" tabindex="-1">标签属性图 <a class="header-anchor" href="#标签属性图" aria-label="Permalink to “标签属性图”">​</a></h3><p>Neo4j 使用标签属性图模型，包含：节点（Node）、关系（Relationship）、属性（Property）、标签（Label）、路径（Path）。</p><p>节点是实体，可以有多个标签和多个属性。关系是节点之间的有向边，必须有一个类型（Type）和至少两个属性（起始节点 ID、结束节点 ID），也可以有其他属性。属性是键值对，值可以是原始类型或数组。标签是节点的分类，一个节点可以有多个标签。路径是节点和关系的交替序列。</p><h3 id="图建模原则" tabindex="-1">图建模原则 <a class="header-anchor" href="#图建模原则" aria-label="Permalink to “图建模原则”">​</a></h3><p>关系数据库通过外键建模关系，查询需要多次 JOIN。图数据库直接存储关系，查询可以遍历关系。例如查询&quot;朋友的朋友&quot;，关系数据库需要多次自 JOIN，图数据库只需要两次关系跳转。</p><p>避免超级节点（super node）：度数很大的节点会遍历大量关系，性能差。例如&quot;所有人关注 Twitter&quot;，该节点的度数是用户数，遍历开销大。解决方案：将时间、分类等维度加入关系，减少度数。</p><h2 id="存储引擎" tabindex="-1">存储引擎 <a class="header-anchor" href="#存储引擎" aria-label="Permalink to “存储引擎”">​</a></h2><h3 id="节点和关系存储" tabindex="-1">节点和关系存储 <a class="header-anchor" href="#节点和关系存储" aria-label="Permalink to “节点和关系存储”">​</a></h3><p>Neo4j 将节点和关系分开存储。节点存储包含：节点 ID、标签、属性 ID、关系的第一个 ID 和第二个 ID（用于双向遍历）。关系存储包含：关系 ID、类型、属性 ID、起始节点 ID、结束节点 ID、前一个关系 ID、下一个关系 ID（用于起始节点的关系链）、前一个关系 ID、下一个关系 ID（用于结束节点的关系链）。</p><p>节点的关系链组织成一个双向链表，通过起始节点的关系 ID 可以遍历所有关系。关系链是双向的，可以正向和反向遍历。</p><h3 id="属性存储" tabindex="-1">属性存储 <a class="header-anchor" href="#属性存储" aria-label="Permalink to “属性存储”">​</a></h3><p>属性存储在属性链中，每个属性是一个键值对。同一个节点或关系的属性链式组织，通过属性 ID 链接。属性值可以是原始类型或数组，数组的每个元素存储在单独的记录中。</p><p>属性存储是独立的，节点和关系只存储属性 ID，通过属性 ID 查找属性。这种设计避免了重复存储属性，但增加了查找开销。</p><h3 id="固定大小记录" tabindex="-1">固定大小记录 <a class="header-anchor" href="#固定大小记录" aria-label="Permalink to “固定大小记录”">​</a></h3><p>Neo4j 的存储记录是固定大小的，便于内存映射和缓存。节点记录 9 字节，关系记录 33 字节，属性记录 41 字节。固定大小记录可以直接通过 ID 计算 offset，支持 O(1) 访问。</p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to “缓存”">​</a></h3><p>Neo4j 使用两层缓存：页面缓存（Page Cache，缓存数据页）和对象缓存（Object Cache，缓存节点和关系对象）。页面缓存是操作系统的文件缓存，使用 mmap 映射文件到内存。对象缓存是 Neo4j 的缓存，缓存热点的节点和关系。</p><h2 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to “索引”">​</a></h2><h3 id="schema-索引" tabindex="-1">Schema 索引 <a class="header-anchor" href="#schema-索引" aria-label="Permalink to “Schema 索引”">​</a></h3><p>Schema 索引是用户显式创建的索引，支持单个属性或多个属性（复合索引）。索引类型：btree（默认，支持范围查询）、fulltext（全文检索）、point（空间索引）。索引通过 Cypher 创建：CREATE INDEX ON :Person(name)。</p><p>Schema 索引加速查找：WHERE name = &#39;Alice&#39; 会使用 name 索引快速定位节点。索引会自动维护，插入、更新、删除节点时更新索引。</p><h3 id="全文索引" tabindex="-1">全文索引 <a class="header-anchor" href="#全文索引" aria-label="Permalink to “全文索引”">​</a></h3><p>全文索引基于 Apache Lucene，支持文本搜索。全文索引需要显式创建：CREATE FULLTEXT INDEX FOR (n:Person) ON EACH [n.name]。全文索引支持 CONTAINS、STARTS WITH 等查询。</p><h3 id="自动索引" tabindex="-1">自动索引 <a class="header-anchor" href="#自动索引" aria-label="Permalink to “自动索引”">​</a></h3><p>Neo4j 早期版本有自动索引，为每个标签的每个属性自动创建索引。自动索引已废弃，建议使用 Schema 索引。</p><h3 id="约束" tabindex="-1">约束 <a class="header-anchor" href="#约束" aria-label="Permalink to “约束”">​</a></h3><p>约束是特殊的索引，保证数据唯一性或存在性。唯一约束：CREATE CONSTRAINT ON (p:Person) ASSERT p.id IS UNIQUE。存在性约束：CREATE CONSTRAINT ON (p:Person) ASSERT exists(p.name)。约束可以加速查找，同时保证数据完整性。</p><h2 id="cypher-查询语言" tabindex="-1">Cypher 查询语言 <a class="header-anchor" href="#cypher-查询语言" aria-label="Permalink to “Cypher 查询语言”">​</a></h2><h3 id="查询结构" tabindex="-1">查询结构 <a class="header-anchor" href="#查询结构" aria-label="Permalink to “查询结构”">​</a></h3><p>Cypher 是声明式图查询语言，类似于 SQL 的图版本。查询结构：MATCH（模式匹配）、WHERE（过滤）、RETURN（返回结果）、ORDER BY（排序）、LIMIT（限制）、SKIP（跳过）。</p><h3 id="模式匹配" tabindex="-1">模式匹配 <a class="header-anchor" href="#模式匹配" aria-label="Permalink to “模式匹配”">​</a></h3><p>Cypher 的核心是模式匹配（Pattern Matching），使用 ASCII 图表示节点和关系。例如：MATCH (p:Person)-[:KNOWS]-&gt;(f:Person) WHERE p.name = &#39;Alice&#39; RETURN f.name 表示查找 Alice 认识的人。</p><p>模式匹配支持：变长关系（-[:KNOWS*1..3]-&gt;，1 到 3 跳）、最短路径（shortestPath）、任意路径（allShortestPaths）。</p><h3 id="查询执行" tabindex="-1">查询执行 <a class="header-anchor" href="#查询执行" aria-label="Permalink to “查询执行”">​</a></h3><p>Cypher 查询执行经历：解析成逻辑计划、优化逻辑计划、生成物理计划、执行物理计划。优化器基于规则（RBO）和成本（CBO），考虑索引、选择性、查询模式。</p><p>物理计划包含多个算子：NodeByIndexScan（索引扫描节点）、NodeByLabelScan（标签扫描节点）、Expand（展开关系）、Filter（过滤）、Projection（投影）、Sort（排序）。</p><h3 id="查询优化" tabindex="-1">查询优化 <a class="header-anchor" href="#查询优化" aria-label="Permalink to “查询优化”">​</a></h3><p>使用索引加速查找：WHERE name = &#39;Alice&#39; 应该在 name 上创建索引。避免笛卡尔积：MATCH (a:A), (b:B) 会产生 A 和 B 的笛卡尔积，应该使用关系连接：MATCH (a:A)-[:REL]-&gt;(b:B)。</p><p>使用 PROFILE 查看执行计划，分析性能瓶颈。使用 EXPLAIN 查看执行计划，不实际执行查询。</p><h2 id="高可用" tabindex="-1">高可用 <a class="header-anchor" href="#高可用" aria-label="Permalink to “高可用”">​</a></h2><p>###因果集群</p><p>Neo4j 企业版支持因果集群（Causal Cluster），包括核心服务器（Core Server）和只读副本（Read Replica）。核心服务器使用 Raft 协议复制数据，保证强一致性。只读副本异步复制数据，可以处理读请求。</p><h3 id="备份与恢复" tabindex="-1">备份与恢复 <a class="header-anchor" href="#备份与恢复" aria-label="Permalink to “备份与恢复”">​</a></h3><p>Neo4j 支持全量备份和增量备份。全量备份复制整个数据目录，增量备份复制事务日志。恢复时，先恢复全量备份，然后重放事务日志。</p><p>Neo4j 是专业的图数据库，适合社交网络、知识图谱、欺诈检测等场景。理解它的实现，有助于设计图模型、优化查询和规划集群架构。</p>',48)])])}const m=e(l,[["render",i]]);export{b as __pageData,m as default};
